Here's the Fibonacci series code in C, C++, Python, Java, and PHP:

**C**

```c
#include <stdio.h>

int main() {
  int n, i, t1 = 0, t2 = 1, nextTerm;

  printf("Enter the number of terms: ");
  scanf("%d", &n);

  printf("Fibonacci Series: ");

  for (i = 1; i <= n; ++i) {
    printf("%d, ", t1);
    nextTerm = t1 + t2;
    t1 = t2;
    t2 = nextTerm;
  }
  return 0;
}
```

**C++**

```cpp
#include <iostream>

int main() {
  int n, i, t1 = 0, t2 = 1, nextTerm;

  std::cout << "Enter the number of terms: ";
  std::cin >> n;

  std::cout << "Fibonacci Series: ";

  for (i = 1; i <= n; ++i) {
    std::cout << t1 << ", ";
    nextTerm = t1 + t2;
    t1 = t2;
    t2 = nextTerm;
  }
  return 0;
}
```

**Python**

```python
def fibonacci(n):
    a, b = 0, 1
    for i in range(n):
        print(a, end=", ")
        a, b = b, a + b

n = int(input("Enter the number of terms: "))
print("Fibonacci Series: ")
fibonacci(n)
```

**Java**

```java
import java.util.Scanner;

public class Fibonacci {
    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        int n, i, t1 = 0, t2 = 1, nextTerm;

        System.out.print("Enter the number of terms: ");
        n = input.nextInt();

        System.out.print("Fibonacci Series: ");

        for (i = 1; i <= n; ++i) {
            System.out.print(t1 + ", ");
            nextTerm = t1 + t2;
            t1 = t2;
            t2 = nextTerm;
        }
    }
}
```

**PHP**

```php
<?php
function fibonacci($n){
    $a = 0;
    $b = 1;
    for ($i = 0; $i < $n; $i++){
        echo $a . ", ";
        $temp = $b;
        $b = $a + $b;
        $a = $temp;
    }
}

$n = readline("Enter the number of terms: ");
echo "Fibonacci Series: ";
fibonacci($n);
?>
```
